const PiranhaMessage = require('../../PiranhaMessage')

class NpcSectorStateMessage extends PiranhaMessage {
  constructor (client) {
    super()
    this.id = 21903
    this.client = client
    this.version = 1
  }

  async encode () {
    this.writeHex('00210B0017CFFBD5D9DBB8F2027F7F7F7F0000000000007F3600942D000000000000000006000000000000000000090000000000000000')
    this.writeByte(2)
    this.writeLong(0, 1) // HighID, LowID
    this.writeByte(2)
    this.writeLong(0, 1) // HighID, LowID
    this.writeByte(2)
    this.writeLong(0, 1) // HighID, LowID
    this.writeString('Berkania')
    this.writeHex('')
    this.writeHex('01A5030000')
  }
}

module.exports = NpcSectorStateMessage